import { useEffect } from "react";

export function useArticleMeta({
  lang = "et",
  title,
  description,
  metaTags = [],
  structuredData,
  schemaId,
}) {
  useEffect(() => {
    const previousLang = document.documentElement.lang;
    const previousTitle = document.title;

    document.documentElement.lang = lang;
    if (title) {
      document.title = title;
    }

    const managedMeta = (metaTags || []).map((meta) => {
      const selector = meta.name ? `meta[name="${meta.name}"]` : `meta[property="${meta.property}"]`;
      const existing = document.head.querySelector(selector);

      if (existing) {
        const prevContent = existing.getAttribute("content");
        existing.setAttribute("content", meta.content);
        return { element: existing, prevContent };
      }

      const element = document.createElement("meta");
      if (meta.name) {
        element.setAttribute("name", meta.name);
      }
      if (meta.property) {
        element.setAttribute("property", meta.property);
      }
      element.setAttribute("content", meta.content);
      document.head.appendChild(element);
      return { element, isNew: true };
    });

    let script;
    if (structuredData) {
      script = document.createElement("script");
      script.type = "application/ld+json";
      if (schemaId) {
        script.id = schemaId;
      }
      script.textContent = JSON.stringify(structuredData);
      document.head.appendChild(script);
    }

    return () => {
      document.documentElement.lang = previousLang;
      document.title = previousTitle;

      managedMeta.forEach(({ element, prevContent, isNew }) => {
        if (isNew) {
          element.remove();
        } else if (prevContent) {
          element.setAttribute("content", prevContent);
        }
      });

      if (script && script.parentNode) {
        script.parentNode.removeChild(script);
      }
    };
  }, [lang, title, description, metaTags, structuredData, schemaId]);
}

