import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "miks-on-oluline-jalgida-olirohku";
const META_TITLE = "Miks on oluline jälgida õlirõhku ja mida madal rõhk tegelikult tähendab?";
const META_DESCRIPTION =
  "Selgitame, miks õlirõhk on kriitiline, mis põhjustab madalat õlirõhku ning kuidas vanemal autol riske ennetada.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "õlirõhk, madal õlirõhk, vanema auto hooldus",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogMiksOnOlulineJalgidaOlirohku() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-miks-on-oluline-jalgida-olirohku",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Miks on oluline jälgida õlirõhku ja mida madal rõhk tegelikult tähendab?</Heading>

          <p>
            Vanematel autodel on <strong>õlirõhk</strong> üks olulisemaid näitajaid, mille ignoreerimine lõppeb kiire ja
            kalli mootoririketega. Kui punane õlikann süttib või rõhk on näidiku järgi kahtlaselt madal, ei ole see „veidi
            ebamugav“, vaid otsene STOP-signaal.
          </p>

          <Heading as="h2">Mida õlirõhk päriselt teeb?</Heading>
          <p>
            Õlirõhk tagab, et mootori laagrid, nukkvõll ja muu liikuv siseehitus saavad pidevalt õlikile vahele. Ilma
            piisava rõhuta tekib <strong>metall-metall kontakt</strong>, mis mõne minuti jooksul võib hävitada väntvõlli
            ja laagrid.
          </p>

          <Heading as="h2">Madal õlirõhk tühikäigul – kas see on alati ohtlik?</Heading>
          <p>
            Vanematel mootoritel võib tühikäigul näidik näidata madalamat rõhku kui uusauto kataloogis. Kui{" "}
            <strong>rõhk tõuseb kohe pöörete lisamisel</strong> ja hoiatuslamp ei sütti, võib see olla kulumisest tulenev,
            kuid mitte veel kriitiline. Sellegipoolest tasub kontrollida õli viskoossust ja kvaliteeti.
          </p>

          <Heading as="h2">Õlitaseme langus – kõige lihtsam põhjus</Heading>
          <p>
            Esimene kontroll vanal autol: <strong>õlivarras</strong>. Kui tase on miinimumist allpool, langeb ka rõhk.
            Pidev madal tase viitab kas lekkimisele, õlikulule või mõlemale.
          </p>

          <Heading as="h2">Vale või väsinud õli</Heading>
          <p>
            Liiga vedel või ära väsinud õli ei suuda vanas mootoris <strong>rõhku hoida</strong>. Siin aitab õige
            viskoossuse valik ja lühendatud õlivahetusintervall. 0W-20 või väga vedel õli väsinud mootoris on enamasti halb
            kombinatsioon.
          </p>

          <Heading as="h2">Õlipump, sõel ja kanalid</Heading>
          <p>
            Kui rõhk on madal hoolimata korrektsest õlitasemest ja õlist, on järgmisel kahtlusalusel:
            <strong>õlipump ja õlivõtja sõel</strong>. Sete ja mustus võivad sõela ummistada, pumba kulumine aga vähendada
            tootlikkust. See on juba olukord, mis vajab töökoja sekkumist.
          </p>

          <Heading as="h2">Andur või reaalne probleem?</Heading>
          <p>
            Vahel on süüdlane lihtsalt <strong>vigane õlirõhuandur</strong>. Aga mängureegel on lihtne: kuni pole tõestatud,
            et andur valetab, tuleb arvestada, et häire on päris. Esmalt kontroll, siis vajadusel anduri vahetus.
          </p>

          <Heading as="h2">Kokkuvõte: õlirõhu hoiatustuli ei ole dekoratsioon</Heading>
          <p>
            <strong>Madal õlirõhk vanal autol</strong> on kriitiline signaal, mille ignoreerimine võib tappa mootori minutitega.
            Regulaarne õlivahetus, õige viskoossus ja süsteemne diagnostika on odavamad kui väntvõlli remont või mootori vahetus.
          </p>
        </article>
      </main>
    </div>
  );
}

