import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "kliimaseadme-ja-salongisoojenduse-hooldus";
const META_TITLE = "Kliimaseadme ja salongisoojenduse hooldus – miks klaasid uduseks lähevad?";
const META_DESCRIPTION =
  "Selgitame, miks vanematel autodel hakkavad klaasid rohkem uduseks minema ja kuidas kliimaseadme ning salongisoojenduse hooldus probleemi lahendab.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "kliimaseade hooldus, salongifilter, udu klaasil",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogKliimaseadmeJaSalongisoojenduseHooldus() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-kliimaseadme-ja-salongisoojenduse-hooldus",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Kliimaseadme ja salongisoojenduse hooldus – miks vanematel autodel hakkab klaas rohkem uduseks minema?</Heading>

          <p>
            Kui auto klaasid muutuvad pidevalt uduseks, eriti sügisel ja talvel, ei ole süüdi ainult „halb ilm“. Vanematel autodel viitab see tihti
            <strong>kliimaseadme, salongisoojenduse või niiskuse juhtimise probleemidele</strong>.
          </p>

          <Heading as="h2">Umbe läinud salongifilter</Heading>
          <p>
            <strong>Salongifilter</strong> on esimene komponent, mille poole vaadata. Kui see on must, niiske ja ummistunud, ei pääse värske õhk korralikult salongi.
            Ventilaator peab rohkem pingutama, õhuvahetus on kehv ja niiskus koguneb salongi, mitte ei liigu välja.
          </p>

          <Heading as="h2">Niiskus autos – kummimatid, märjad tekstiilid ja lekkivad tihendid</Heading>
          <p>
            Vanemate autode ukselingid, klaasitihendid ja uksetihendid ei pruugi enam olla 100% tihedad. Vihmavesi ja lumesodi satuvad salongi, eriti kui kasutatakse
            <strong>kummimatte ilma õige äravooluta</strong>. Püsiv niiskus põrandal = pidev udu klaasidel.
          </p>

          <Heading as="h2">Kliimaseade ei kuivatagi enam õhku</Heading>
          <p>
            Kliimaseade ei ole ainult „külma tegemiseks“. Ta <strong>kuivatab õhku</strong>, mis on udu tekkimise seisukohast kriitiline. Kui kliimaseade ei jahuta ega kuivat enam korralikult
            (gaasipuudus, lekked, ummistunud radikas), ei saa süsteem niiskust salongist kätte.
          </p>

          <Heading as="h2">Soojendusradika lekked</Heading>
          <p>
            Kui salongis on magus lõhn, klaasid lähevad kiiresti uduseks ja klaasile tekib õline kiht, võib olla lekkimas <strong>salongisoojenduse radikas</strong>. Jahutusvedelik aurustub salongi,
            tõstab niiskust ja tekitab udu – see on juba turvalisust ja tervist mõjutav probleem.
          </p>

          <Heading as="h2">Ventilaator ja siibrihoovastik</Heading>
          <p>
            Vanematel autodel kuluvad <strong>ventika mootorid, takistid ja klappide hoovastikud</strong>. Kui õhk ei liigu õigesse suunda (nt klaasile), ei saa süsteem ka kõige parema kliimaga udu kiirelt
            eemaldada. Kontrollida tasub, kas kõik puhumisasendid töötavad loogiliselt.
          </p>

          <Heading as="h2">Harjumused: “ringluse” nupp ja vale kasutus</Heading>
          <p>
            Püsivalt sees olev <strong>sisemise ringluse režiim</strong> tähendab, et sama niiske õhk tiirutab autos ringi. Udu ei kao, vaid süveneb. Õige kasutus: niiskuse eemaldamiseks hoida värske õhu režiim
            sees ja vajadusel kasutada kliimat + sooja koos.
          </p>

          <Heading as="h2">Kokkuvõte: udu klaasil on süsteemi, mitte ilma probleem</Heading>
          <p>
            <strong>Klaaside uduseks minek vanemal autol</strong> on väga selge signaal, et kliimaseadet, salongisoojendust, salongifiltrit ja tihendeid on vaja üle vaadata.
            Hästi hooldatud süsteem hoiab nägemise selge ja sõidu ohutu ka pimedatel ja niisketel päevadel.
          </p>
        </article>
      </main>
    </div>
  );
}
