import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "suutesusteem-ja-katalusaator";
const META_TITLE = "Süüteküünlad, süütepoolid ja juhtmed – miks “väike jõnks” võib rikkuda katalüsaatori?";
const META_DESCRIPTION =
  "Selgitame, kuidas süüteprobleemid tekitavad jõnksutamist, miks põlemata kütus hävitab katalüsaatori ning miks süütesüsteemi ei tasu ignoreerida.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "süüteküünlad, süütepoolid, katalüsaator",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogSuutesusteemJaKatalusaator() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-suutesusteem-ja-katalusaator",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Süüteküünlad, süütepoolid ja juhtmed – miks “väike jõnks” võib rikkuda katalüsaatori?</Heading>

          <p>
            Enamik juhte tunneb selle ära: <strong>väike jõnks kiirendusel</strong>, aeg-ajalt katkestus, korraks võtab jõu maha. Mõeldakse: „ah, küll sõidab“. Tegelikult on see süütesüsteemi SOS, mis võib kiiresti lõppeda <strong>katalüsaatori surmaga</strong>.
          </p>

          <Heading as="h2">Kuidas süütesüsteemi viga välja näeb?</Heading>
          <p>Tüüpilised sümptomid:</p>
          <ul>
            <li>jõnksutamine kiirendusel, eriti madalatel pööretel;</li>
            <li>mootori värisemine tühikäigul;</li>
            <li>check engine tuli (tihti vilkuv süütekatkestuse korral);</li>
            <li>ebaregulaarne heli summutist.</li>
          </ul>

          <Heading as="h2">Mis toimub, kui silinder ei sütti?</Heading>
          <p>Kui <strong>süüteküünal, pool või kaabel ei tööta</strong>, liigub põlemata kütus väljalaskesse. Katalüsaator üritab selle hiljem põletada, temperatuur tõuseb kriitiliseks ja kärg <strong>sulab või murdub</strong>.</p>

          <Heading as="h2">Miks katalüsaatori remont on valusam kui süütesüsteemi hooldus?</Heading>
          <p>Uus katalüsaator on kallis varuosa, lisandub tööraha ja risk heitgaasidega tehnoülevaatusel. Võrdluseks on <strong>süüteküünlad, poolid ja kaablid</strong> kordades odavamad.</p>

          <Heading as="h2">Mis süütesüsteemi vanemal autol tapab?</Heading>
          <ul>
            <li>kõrge läbisõit ja kunagi vahetamata küünlad;</li>
            <li>odavad või valed küünlad;</li>
            <li>kuumuse ja vibratsiooni käes väsivad <strong>süütepoolid</strong>;</li>
            <li>vanadel süsteemidel pragunema ja oksüdeeruma kippuvad <strong>süütejuhtmed</strong>.</li>
          </ul>

          <Heading as="h2">Millal lasta süütesüsteem üle kontrollida?</Heading>
          <p>Kohe, kui märkad esimesi jõnksusid kiirendusel, check engine vilgub koormuse all või mootor töötab vihmaga halvemini.</p>

          <Heading as="h2">Proaktiivne hooldus</Heading>
          <p>
            Mõistlik taktika on vahetada süüteküünlad tootja intervalli järgi või varem (eriti gaasiautodel), kontrollida poolide ja kaablite seisukorda ning mitte ignoreerida ühtegi süütekatkestuse sümptomit.
          </p>

          <Heading as="h2">Kokkuvõte</Heading>
          <p>
            <strong>Süütesüsteemi rikked</strong> on üks odavamaid asju, mida õigel ajal lahendada – ja üks kulukamaid, kui neid ignoreerida. Väike jõnks täna võib olla katalüsaatori surm homme.
          </p>
        </article>
      </main>
    </div>
  );
}
