import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "amortisaatorid-ja-vanem-auto";
const META_TITLE = "Amortisaatorid ja vanem auto – kuidas aru saada, et amort on läbi?";
const META_DESCRIPTION =
  "Vaatame, kuidas tuvastada kulunud amortisaatorid enne, kui tehnoülevaatus need läbi kukutab – märgid teel, pidurdusel ja kurvides.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "amortisaatorid, pidurdusteekond, veermiku hooldus",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogAmortisaatoridJaVanemAuto() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-amortisaatorid-ja-vanem-auto",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Amortisaatorid ja vanem auto – kuidas aru saada, et amort on „läbi“, enne kui ülevaatus seda ütleb?</Heading>

          <p>
            Amort ei lähe läbi üleöö – ta väsib aeglaselt. Juht harjub järk-järgult ujuva käitumisega ega pane muutust tähele, kuni tehnoülevaatus või avarii teeb reaalsuse selgeks. Õigeaegne <strong>amortide vahetus</strong> on otseselt ohutusinvesteering.
          </p>

          <Heading as="h2">Märgid sõidu ajal, et amort on väsinud</Heading>
          <ul>
            <li>Auto jääb <strong>„õõtsuma“ pärast lainet või auku</strong> – ei rahune kiiresti maha;</li>
            <li>Kurvis on tunda ebakindlust, auto kaldub rohkem kui varem;</li>
            <li>Pidurdamisel „nokkab“ nina tugevalt alla;</li>
            <li>Tuulise ilmaga on auto juhitavus ujuv ja närviline.</li>
          </ul>

          <Heading as="h2">Visuaalsed märgid: õli ja mustus amordi peal</Heading>
          <p>
            Kui amordi korpuse peal on <strong>õlised ja tolmused triibud</strong>, on tegu lekkiva amortisaatoriga. Lekkiv amort ei summuta enam lööke – sisuliselt sõidad vedrude ja pukside peal.
          </p>

          <Heading as="h2">Kuidas amort mõjutab pidurdusteekonda?</Heading>
          <p>
            Väsinud amordi puhul kaotab rehv ebatasasusel <strong>kontakti teega</strong>. ABS sekkub rohkem, pidurdamine muutub hüplikuks ja pidurdusteekond pikeneb. Seda mõju ei näe enne, kui teed hädapidurduse, kuid siis on juba hilja mõelda.
          </p>

          <Heading as="h2">Miks vahetada amorte paaris, mitte üksikult?</Heading>
          <p>
            Kui ühel teljel vahetada ainult üks amort, on telje käitumine <strong>tasakaalust väljas</strong>. Standardpraktika on vahetada amorte vähemalt telje kaupa.
          </p>

          <Heading as="h2">Vanem auto ja veermik: miks amort ei ole koht, kust raha kokku hoida?</Heading>
          <p>
            Vanemal autol on veermik niigi väsinum. Halvad amortisaatorid koormavad üle <strong>pukse, šarniire ja kinnitusi</strong>, tekitavad rohkem lööke keresse ja lõhuvad kiiremini ka rehve.
          </p>

          <Heading as="h2">Kokkuvõte: amortide vahetus enne, mitte pärast probleemi</Heading>
          <p>
            Kui märkad mõnda neist sümptomitest, tasub teha <strong>veermiku kontroll</strong> ja lasta amortidel professionaalselt hinnata. Amort ei ole luksus – see hoiab ratta teega kontaktis igas olukorras.
          </p>
        </article>
      </main>
    </div>
  );
}
