import React from 'react';
import { Star } from 'lucide-react';
import { cn } from '../../lib/utils';

const ReviewMarquee = ({ reviews }) => {
  return (
    <div className="overflow-hidden bg-gradient-to-r from-blue-50 to-green-50 dark:from-blue-900/20 dark:to-green-900/20 rounded-lg p-4" aria-label="Customer reviews">
      <div className="flex animate-marquee" aria-live="polite">
        {reviews.concat(reviews).map((review, index) => (
          <div
            key={index}
            className="flex-shrink-0 w-80 mx-4 flex items-center gap-3"
            role="article"
            aria-label={`Review by ${review.author}: ${review.text}`}
          >
            <div className="flex text-yellow-400" role="img" aria-label="5 tärni hinnang">
              {[...Array(5)].map((_, i) => (
                <Star key={i} className="w-4 h-4 fill-current" aria-hidden="true" />
              ))}
            </div>
            <p className="text-sm text-gray-700 dark:text-gray-300 italic">
              "{review.text}"
            </p>
            <span className="text-xs text-gray-500 dark:text-gray-400">
              — {review.author}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
};

export { ReviewMarquee };
