import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "vaikesed-olilekked";
const META_TITLE = "Väikesed õlilekked, suured riskid: tuleohutus ja keskkond 2025. aastal";
const META_DESCRIPTION =
  "Selgitame, miks isegi väike õlileke on tänapäeval tuleohutuse, keskkonna ja tehnilise ülevaatuse mõttes tõsine risk ning miks reageerida kohe.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "õlileke, tuleohutus, keskkonnarisk",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogVaikesedOlilekked() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-vaikesed-olilekked",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <header>
            <Heading as="h1">Väikesed õlilekked, suured riskid: tuleohutus ja keskkond 2025. aastal</Heading>
            <h2>Alternatiivsed pealkirjad</h2>
            <ul>
              <li>“Natuke tilgub” ei ole enam okei: õlilekked ja tehniline ülevaatus</li>
              <li>Miks väike õlileke võib lõppeda suure tulekahjuga?</li>
              <li>Õlilaigud parklas: keskkonnariski hind, mitte “vana auto eripära”</li>
            </ul>
            <p>
              Mõtteviis “vana auto ikka veidi tilgub” on 2025. aastaks aegunud. Väikesed õlilekked ei tähenda ainult musta mootorit – need on tuleohutuse, keskkonna ja tehnilise ülevaatuse vaates väga konkreetne risk.
            </p>
          </header>

          <section>
            <Heading as="h2">Miks väike õlileke on tehniliselt suur probleem?</Heading>
            <ul>
              <li><strong>Õli kuumadel pindadel:</strong> reaalne tulekahju risk väljalaskekollektori või turbo ümbruses.</li>
              <li><strong>Lisakahjud:</strong> õli lagundab kummidetaile, mustus tekitab “õlimuda”, mis sööb pistikuid.</li>
              <li><strong>Varjatud lekked:</strong> nähtav tilk on tihti vaid osa probleemist.</li>
            </ul>
          </section>

          <section>
            <Heading as="h2">Tehniline ülevaatus ja regulatiivne reaalsus</Heading>
            <p>Ülevaatuspunktid on karmimad ja märkus “õlileke” võib tähendada läbikukkumist. Suured õlilaigud parklas toovad kaasa vaidlusi ja mainekahju.</p>
          </section>

          <section>
            <Heading as="h2">Keskkonnamõju</Heading>
            <p>Tilkunud õli liigub vihmaga kanalisatsiooni ja edasi veekogudesse. Keskkonnateadlikkus on uus baasstandard.</p>
          </section>

          <section>
            <Heading as="h2">Miks “natuke tilgub” ei ole enam OK?</Heading>
            <p>Väike leke kipub ajas kasvama. Varajane sekkumine tähendab tihti ainult tihendi vahetust; hiljem lisanduvad mootorikahjud ja tuleohuriskid.</p>
          </section>

          <section>
            <Heading as="h2">Nägid autot alla tekkivat õlilaiku?</Heading>
            <p>
              <a href="/kontakt">Lepi Nisbeliga kokku lekkeaudit</a>. Kaardistame allikad, hindame riski ja pakume remondiplaani.
            </p>
          </section>
        </article>
      </main>
    </div>
  );
}
