import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "hammasrihma-vahetus";
const META_TITLE = "Hammasrihma vahetus – miks „umbes“ ei tööta?";
const META_DESCRIPTION =
  "Hammasrihma vahetusintervall ei ole soovituslik. Selgitame, mis juhtub, kui venitada rihm üle tootja piiride ja miks see lõpeb sageli kalli mootoriremondiga.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "hammasrihm, vahetusintervall, mootoriremont",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogHammasrihmaVahetus() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-hammasrihma-vahetus",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Hammasrihma vahetus – miks „umbes“ ei tööta?</Heading>

          <p>
            Hammasrihma puhul ei kehti „sõidame veel ühe hooaja“ taktika. <strong>Rihm puruneb ootamatult</strong> ja tagajärg on enamikel mootoritel sama: ventiilid ja kolvid kohtuvad. See tähendab suurt arvet.
          </p>

          <Heading as="h2">Tootja intervall: kilomeetrid ja aastad</Heading>
          <p>
            Enamik tootjaid annab hammasrihmale nii <strong>läbisõidu piiri</strong> kui ka <strong>aja piiri</strong>. Vanematel autodel on tihti kilomeetreid vähem, aga aastaid rohkem. Kummi ja kiud <strong>vananevad ka seistes</strong>, mitte ainult sõites.
          </p>

          <Heading as="h2">Mis juhtub, kui rihm puruneb?</Heading>
          <p>
            Interference-tüüpi mootorites tähendab rihma purunemine, et kolb tabab avatud ventiili, ventiil kõverub ning kahjustuvad plokikaas ja kolvid. See ei ole enam hammasrihma remont, vaid <strong>mootori kapitaalremont või vahetus</strong>.
          </p>

          <Heading as="h2">Kasutatud auto ja teadmata ajalooga rihm</Heading>
          <p>
            Kui auto ostes puudub selge tõend rihma vahetuse kohta, tuleb lähtuda halvimast ja planeerida töö kohe. Ilma tõenduseta on <strong>rihm teadmata seisus</strong>.
          </p>

          <Heading as="h2">Miks visuaalne vaatamine ei piisa?</Heading>
          <p>
            Rihm võib välja näha korras, kuid sisemine kiud võib olla väsinud. Mikropragud peituvad hammaste juures ning niiskus, õli ja temperatuur teevad oma töö tasapisi. Seetõttu ei saa üksnes välimusele toetuda.
          </p>

          <Heading as="h2">Kokkuvõte: hammasrihm ei küsi, kas sul on parasjagu raha</Heading>
          <p>
            <strong>Hammasrihma vahetus</strong> õigel ajal on odav kindlustus. Kui rihm puruneb, ei küsi mootor, kas on palgapäev või mitte – ta lihtsalt laguneb. Seetõttu tasub intervalli järgida ja planeerida vahetus teadlikult ette.
          </p>
        </article>
      </main>
    </div>
  );
}
